export const TriggerElement = () => {
  const btnRef = useRef();
  const [rangeValue, setRangeValue] = React.useState<[moment.Moment?, moment.Moment?]>([undefined, undefined]);

  const renderDatePickerTriggerElement = ({ text, hoverText, value }: DatePickerState) => {
    console.log(value);
    return <Button ref={btnRef}>Data: {text || hoverText}</Button>;
  };

  const renderRangePickerTriggerElement = ({ startText, endText }: RangePickerState) => (
    <Button>
      Data: {startText} - {endText}{' '}
    </Button>
  );

  return (
    <Space>
      <DatePicker defaultOpen={__SCREENSHOT__} triggerElement={renderDatePickerTriggerElement} />
      <DatePicker defaultOpen={__SCREENSHOT__} triggerElement={<Button>123</Button>} />
      <DatePicker.RangePicker
        defaultOpen={__SCREENSHOT__}
        value={rangeValue}
        triggerElement={renderRangePickerTriggerElement}
        onChange={setRangeValue}
      />
      <DatePicker.RangePicker
        value={rangeValue}
        triggerElement={
          <Button>
            {rangeValue[0]?.format('MM/DD/YYYY') ?? '未选择'}
            {' - '}
            {rangeValue[1]?.format('MM/DD/YYYY') ?? '未选择'}
          </Button>
        }
        onChange={setRangeValue}
      />
      <DatePicker.RangePicker defaultOpen={__SCREENSHOT__} triggerElement={<Button>123</Button>} />
      <Button onClick={() => console.log(btnRef.current)}>console ref</Button>
    </Space>
  );
};

