export const ShowTime = () => {
  const [showTime, setShowTime] = useState(false);
  const [needConfirm, setNeedConfirm] = useState(true);
  const [showNow, setShowNow] = useState(showTime);
  const [format, setFormat] = useState('YYYY DD MM HH:mm:ss');
  return (
    <Space>
      <Space direction="vertical">
        <span>
          showTime：
          <Switch onChange={v => setShowTime(v)} checked={showTime} />
        </span>
        <span>
          开启二次确认：
          <Switch checked={needConfirm} onChange={v => setNeedConfirm(v)} />
        </span>
        <span>
          showNow
          <Switch checked={showNow} onChange={v => setShowNow(v)} />
        </span>
        <span>
          时间格式：
          <Select
            value={format}
            onChange={value => setFormat(value as string)}
            options={[
              { value: 'YYYY DD MM HH:mm:ss' },
              { value: 'YYYY DD MM HH:mm' },
              { value: 'YYYY DD MM hh:mm:ss' },
            ]}
          />
        </span>
      </Space>

      <DatePicker
        format={format}
        needConfirm={needConfirm}
        showTime={showTime}
        defaultPickerValue={moment('01/01/2022')}
        showNow={showNow}
        onChange={v => toast.success(`选择了 ${moment(v).format(format)}`)}
        defaultOpen
        open
      />
    </Space>
  );
};

