export const Cursor = () => {
  const [customeControlledOpen, setCustomeControlledOpen] = React.useState(true);

  return (
    <>
      <div style={{ marginBottom: 500 }}>
        1. normal
        <RangePicker />
      </div>
      <div style={{ marginBottom: 500 }}>
        2. defaultOpen
        <RangePicker defaultOpen />
      </div>
      <div style={{ marginBottom: 500 }}>
        3. 强制 open
        <RangePicker open />
      </div>
      <div style={{ marginBottom: 500 }}>
        4. 用户可使用 onOpenChange 手动控制 open
        <RangePicker open={customeControlledOpen} onOpenChange={_open => setCustomeControlledOpen(_open)} />
      </div>
    </>
  );
};

export const RenderExtraFooter = () => {
  const [value, setValue] = React.useState<moment.Moment | undefined>(moment());
  const [tempValue, setTempValue] = React.useState<moment.Moment | undefined>(value);
  return (
    <>
      <h6>用户可使用 renderExtraFooter 实现二次确认功能 {value?.format('MM-DD')}</h6>
      <DatePicker
        needConfirm
        onSelect={v => {
          setTempValue(v);
        }}
        onChange={v => {
          setValue(v);
        }}
        value={value}
        renderExtraFooter={ctx => (
          <Space
            style={{
              padding: 8,
            }}
          >
            <Button
              size="small"
              type="text"
              onClick={() => {
                ctx.setValue(undefined, false);
                setTempValue(undefined);
              }}
            >
              清空
            </Button>
            <Button
              size="small"
              onClick={() => {
                ctx.setValue(value, false);
                setTempValue(value);
              }}
            >
              取消
            </Button>
            <Button
              size="small"
              type="primary"
              onClick={() => {
                ctx.setValue(tempValue, true);
                ctx.setOpened(false);
              }}
            >
              确定
            </Button>
          </Space>
        )}
      />
    </>
  );
};

